import re, json
import jsonschema
from anthropic import Anthropic

client = Anthropic()

def score_case(case: EvalCase, output: str) -> float:
    """Return 0.0–1.0 for this case given the agent's output."""
    match case.check_type:
        case "exact_match":
            return 1.0 if output.strip() == str(case.expected).strip() else 0.0

        case "regex":
            return 1.0 if re.search(str(case.expected), output) else 0.0

        case "json_schema":
            try:
                data = json.loads(output)
                jsonschema.validate(data, case.expected)
                return 1.0
            except (json.JSONDecodeError, jsonschema.ValidationError):
                return 0.0

        case "multi_ref":
            if not case.references:
                return 0.0
            return max(
                1.0 if output.strip() == ref.strip() else 0.0
                for ref in case.references
            )

        case "fn":
            if case.custom_fn is None:
                return 0.0
            return float(case.custom_fn(output))

        case "rubric":
            criteria = "\n".join(f"- {c}" for c in case.rubric_criteria)
            msg = client.messages.create(
                model="claude-haiku-4-5-20251001",
                max_tokens=8,
                messages=[{"role": "user", "content": (
                    f"User request: {case.user_input}\n"
                    f"Agent response: {output}\n\n"
                    f"Score 0.0–1.0 based on:\n{criteria}\n\n"
                    "Return only a float."
                )}],
            )
            try:
                return float(msg.content[0].text.strip())
            except ValueError:
                return 0.0

        case _:
            raise ValueError(f"Unknown check_type: {case.check_type}")

def run_eval_suite(
    cases: list[EvalCase],
    agent_fn,
) -> dict:
    """Run all cases and return aggregate score and per-case results."""
    results = []
    for case in cases:
        output = agent_fn(case.system, case.user_input)
        score  = score_case(case, output)
        results.append({"id": case.id, "score": score, "tags": case.tags})

    total_weight = sum(c.weight for c in cases)
    weighted_score = sum(
        r["score"] * c.weight
        for r, c in zip(results, cases)
    ) / total_weight if total_weight else 0.0

    return {"weighted_score": weighted_score, "cases": results, "n": len(cases)}

from collections import Counter
from statistics import mean

def coverage_report(cases: list[EvalCase]) -> dict:
    """Summarise the test suite across key dimensions."""
    return {
        "total": len(cases),
        "by_difficulty": dict(Counter(c.difficulty for c in cases)),
        "by_source": dict(Counter(c.source for c in cases)),
        "by_check_type": dict(Counter(c.check_type for c in cases)),
        "tag_distribution": dict(
            Counter(tag for c in cases for tag in c.tags).most_common(20)
        ),
        "avg_input_length": mean(len(c.user_input) for c in cases) if cases else 0,
        "weighted_total": sum(c.weight for c in cases),
    }

def coverage_gaps(cases: list[EvalCase]) -> list[str]:
    """List areas likely under-represented in the suite."""
    report = coverage_report(cases)
    gaps = []

    by_diff = report["by_difficulty"]
    if by_diff.get("hard", 0) < report["total"] * 0.15:
        gaps.append(f"Hard cases: only {by_diff.get('hard', 0)} ({by_diff.get('hard', 0)/report['total']:.0%}) — target ≥15%")

    by_source = report["by_source"]
    if by_source.get("prod", 0) < report["total"] * 0.20:
        gaps.append(f"Prod-sourced: only {by_source.get('prod', 0)} — target ≥20% to ensure real-traffic coverage")

    by_check = report["by_check_type"]
    if by_check.get("rubric", 0) > report["total"] * 0.60:
        gaps.append("Over-reliance on rubric checks — replace with regex/exact where possible for determinism")

    tags = report["tag_distribution"]
    for required_tag in ["adversarial", "regression", "edge_case"]:
        if tags.get(required_tag, 0) < 5:
            gaps.append(f"Too few '{required_tag}' cases: {tags.get(required_tag, 0)} found, add at least 5")

    return gaps
